+    pub fn validate(&self) -> Result<(), Vec<String>> {
+        let mut errors = Vec::new();
+
+        if self.schema_version != CLAIM_ENVELOPE_CONTRACT_SCHEMA_VERSION {
+            errors.push(format!(
+                "unexpected schema_version `{}`",
+                self.schema_version
